export type IntegrationAndWebhookTransactionResponse = {
  createdAt?: string;
  id: string;
  integrationId: string;
  integrationResource: IntegrationResource;
  integrationService: IntegrationServices;
  name?: string;
  productType?: ProductType;
  requestBody: string;
  requestHeaders: string;
  responseBody: string;
  responseHeaders: string;
  sourceTable: string;
  status: string;
  statusCode: number | null;
};

export type IntegrationResponse = {
  id: string;
  events?: string[];
  type: string;
  service: IntegrationServices;
  name?: string;
  url?: string;
  createdAt: string;
  resource?: string;
  enabled: boolean;
};

export type IntegrationDestination = ({
  t,
}: Partial<WithIntegrationTFunction & WithIntegrationFormType>) => string | undefined;

export type IntegrationSchemaCustom = ({
  formType,
  serviceTitle,
  t,
}: Partial<WithIntegrationTFunction & WithIntegrationFormType> & { serviceTitle?: string }) =>
  | yup.ObjectShape
  | undefined;

export type IntegrationServiceMap = Map<IntegrationServices, IntegrationService>;

export type IntegrationChange = { id?: string; service?: IntegrationServices };
export type IntegrationChangeCallback = ({ id, service }: IntegrationChange) => void;

export type IntegrationCreateDrawerStep = 'selector' | 'create' | 'update';
export type IntegrationUpdateState = IntegrationChange | null;
export type IntegrationPushState = IntegrationChange | null;

// actionPages is for action pages
// campaigns is for campaigns
// integration switch is if it's not for either of those specifically
// i.e. RumbleUp is an Enabled/Disabled switch
export type IntegrationFormType = 'actionPages' | 'campaigns' | 'integrationSwitch';
export type WithIntegrationFormType = { formType: IntegrationFormType };

export type IntegrationTFunction = TFunction<'integrationDirectory', undefined>;
export type WithIntegrationTFunction = { t: IntegrationTFunction };

/**
 * This initializer either sets a property or provides a function
 * to return the property.
 *
 * And it's based on the form type.
 */
export type FormTypeInitializer<T> = T extends Function
  ? never
  : T | (({ formType }: WithIntegrationFormType) => T | undefined) | undefined;
export type AccountInitializer<T> = T extends Function
  ? never
  : T | (({ currentAccount }: { currentAccount?: IAccountShow }) => T);

export enum ServiceCategory {
  Accounting = 'accounting',
  CRM = 'crm',
  ChMS = 'chms', // church management software
  Compliance = 'compliance',
  DigitalMarketing = 'digitalMarketing',
  EmailMarketing = 'emailMarketing',
  Fulfillment = 'fulfillment',
  Membership = 'membership',
  MobileApp = 'mobileApp',
  Outgoing = 'outgoing',
  SMSDonations = 'smsDonations',
  SMSMarketing = 'smsMarketing',
  SupporterDB = 'supporterDB',
}

// We default these to the appropriate permissions.
// per integration. The override is for integrations
// that don't show by normal rules. e.g., Zapier can
// only be viewed and edited in side drawer by Anedot staff.
type IntegrationPermission = Partial<{
  edit: 'staff';
}>;

export type IntegrationService = {
  Icon: ComponentWithAs<'svg', IconProps>;
  categories?: Set<string>;
  common?: FormTypeInitializer<IntegrationCommonProperties[]>;
  custom?: IntegrationSchemaCustom;
  defaultValues?: FormTypeInitializer<Record<string, IntegrationFieldValue>>;
  destination?: IntegrationDestination;
  extraFields?: FormTypeInitializer<SimpleIntegrationField[]>;
  formType?: IntegrationFormType;

  helpPath?: AccountInitializer<string>;

  isWebhook?: boolean; // e.g., crimson, webhook, zapier

  // oauth settings for services with oauth credentials
  oauth?: {
    // the required oauth params for the integration
    params?: string[];
    required?: boolean; // extra param names for the service
  };

  overrides?: {
    // fields to override to view only
    fields?: Partial<Record<IntegrationCommonProperties, 'view' | undefined>>;
    permissions?: IntegrationPermission;
  };

  title: AccountInitializer<string>;
};

